    rejected_reason text,
    applied_by uuid,
    applied_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    dedup_key character varying(255),
    CONSTRAINT ai_recommendations_category_check CHECK (((category)::text = ANY ((ARRAY['operational'::character varying, 'optimization'::character varying, 'erp'::character varying, 'automation'::character varying, 'risk'::character varying])::text[]))),
    CONSTRAINT ai_recommendations_confidence_score_check CHECK (((confidence_score >= 0) AND (confidence_score <= 100))),
    CONSTRAINT ai_recommendations_impact_level_check CHECK (((impact_level)::text = ANY ((ARRAY['low'::character varying, 'medium'::character varying, 'high'::character varying])::text[]))),
    CONSTRAINT ai_recommendations_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'accepted'::character varying, 'rejected'::character varying, 'applied'::character varying, 'dismissed'::character varying])::text[])))
);


