    reopen_count integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT fiscal_periods_check CHECK ((end_date > start_date)),
    CONSTRAINT fiscal_periods_check1 CHECK ((((status)::text <> 'locked'::text) OR (locked_at IS NOT NULL))),
    CONSTRAINT fiscal_periods_check2 CHECK ((((status)::text <> ALL ((ARRAY['closed'::character varying, 'locked'::character varying])::text[])) OR (closed_at IS NOT NULL))),
    CONSTRAINT fiscal_periods_fiscal_year_check CHECK (((fiscal_year >= 2000) AND (fiscal_year <= 2100))),
    CONSTRAINT fiscal_periods_period_type_check CHECK (((period_type)::text = ANY ((ARRAY['monthly'::character varying, 'quarterly'::character varying, 'semi_annual'::character varying, 'annual'::character varying, 'custom'::character varying])::text[]))),
    CONSTRAINT fiscal_periods_reopen_count_check CHECK ((reopen_count >= 0)),
    CONSTRAINT fiscal_periods_status_check CHECK (((status)::text = ANY ((ARRAY['open'::character varying, 'closed'::character varying, 'locked'::character varying])::text[])))
);


ALTER TABLE public.fiscal_periods OWNER TO smartbiz;

