--
-- Name: inventory_movements; Type: TABLE; Schema: public; Owner: smartbiz
--

CREATE TABLE public.inventory_movements (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    workspace_id uuid NOT NULL,
    warehouse_id uuid NOT NULL,
    product_id uuid NOT NULL,
    variant_id uuid,
    batch_id uuid,
    movement_type character varying(50) NOT NULL,
    quantity_change numeric(12,4) NOT NULL,
    quantity_before numeric(12,4) NOT NULL,
    quantity_after numeric(12,4) NOT NULL,
    unit_cost numeric(12,4),
    total_cost numeric(15,2),
    reference_type character varying(50),
    reference_id uuid,
    created_by uuid,
    reason_code character varying(100),
    notes text,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT inventory_movements_check CHECK ((quantity_after = (quantity_before + quantity_change))),
    CONSTRAINT inventory_movements_check1 CHECK (((((movement_type)::text = ANY ((ARRAY['purchase_receipt'::character varying, 'return_restock'::character varying, 'adjustment_increase'::character varying, 'transfer_in'::character varying, 'production_output'::character varying, 'opening_balance'::character varying])::text[])) AND (quantity_change > (0)::numeric)) OR (((movement_type)::text = ANY ((ARRAY['sale_shipment'::character varying, 'return_dispose'::character varying, 'supplier_return'::character varying, 'adjustment_decrease'::character varying, 'transfer_out'::character varying, 'production_consume'::character varying, 'damage'::character varying, 'shrinkage'::character varying, 'expired'::character varying])::text[])) AND (quantity_change < (0)::numeric)))),
    CONSTRAINT inventory_movements_check2 CHECK (((reference_type IS NULL) OR (((movement_type)::text = 'sale_shipment'::text) AND ((reference_type)::text = 'shipment'::text)) OR (((movement_type)::text = 'purchase_receipt'::text) AND ((reference_type)::text = 'grn'::text)) OR (((movement_type)::text = ANY ((ARRAY['return_restock'::character varying, 'return_dispose'::character varying])::text[])) AND ((reference_type)::text = 'return'::text)) OR (((movement_type)::text = 'supplier_return'::text) AND ((reference_type)::text = 'return'::text)) OR (((movement_type)::text = ANY ((ARRAY['transfer_out'::character varying, 'transfer_in'::character varying])::text[])) AND ((reference_type)::text = 'transfer'::text)) OR (((movement_type)::text = ANY ((ARRAY['production_consume'::character varying, 'production_output'::character varying])::text[])) AND ((reference_type)::text = 'production_order'::text)) OR (((movement_type)::text = ANY ((ARRAY['adjustment_increase'::character varying, 'adjustment_decrease'::character varying, 'damage'::character varying, 'shrinkage'::character varying, 'expired'::character varying])::text[])) AND ((reference_type)::text = 'adjustment'::text)) OR (((movement_type)::text = 'opening_balance'::text) AND ((reference_type)::text = 'opening'::text)))),
    CONSTRAINT inventory_movements_movement_type_check CHECK (((movement_type)::text = ANY ((ARRAY['purchase_receipt'::character varying, 'sale_shipment'::character varying, 'return_restock'::character varying, 'return_dispose'::character varying, 'supplier_return'::character varying, 'adjustment_increase'::character varying, 'adjustment_decrease'::character varying, 'transfer_out'::character varying, 'transfer_in'::character varying, 'production_consume'::character varying, 'production_output'::character varying, 'opening_balance'::character varying, 'damage'::character varying, 'shrinkage'::character varying, 'expired'::character varying])::text[]))),
    CONSTRAINT inventory_movements_quantity_change_check CHECK ((quantity_change <> (0)::numeric)),
    CONSTRAINT inventory_movements_reference_type_check CHECK (((reference_type IS NULL) OR ((reference_type)::text = ANY ((ARRAY['order'::character varying, 'shipment'::character varying, 'grn'::character varying, 'return'::character varying, 'transfer'::character varying, 'production_order'::character varying, 'adjustment'::character varying, 'opening'::character varying])::text[]))))
);
ALTER TABLE ONLY public.inventory_movements ALTER COLUMN workspace_id SET STATISTICS 500;
ALTER TABLE ONLY public.inventory_movements ALTER COLUMN product_id SET STATISTICS 500;


ALTER TABLE public.inventory_movements OWNER TO smartbiz;

