    effective_from date NOT NULL,
    effective_to date,
    CONSTRAINT payroll_statutory_rules_calculation_method_check CHECK (((calculation_method)::text = ANY ((ARRAY['flat'::character varying, 'percentage'::character varying, 'bracket'::character varying])::text[]))),
    CONSTRAINT payroll_statutory_rules_check CHECK (((effective_to IS NULL) OR (effective_to > effective_from)))
);


ALTER TABLE public.payroll_statutory_rules OWNER TO smartbiz;

--
-- Name: TABLE payroll_statutory_rules; Type: COMMENT; Schema: public; Owner: smartbiz
