    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT permission_delegations_check CHECK ((end_at > start_at)),
    CONSTRAINT permission_delegations_check1 CHECK ((delegator_membership_id <> delegate_membership_id)),
    CONSTRAINT permission_delegations_status_check CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'expired'::character varying, 'revoked'::character varying])::text[])))
);


